prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?defs ?defsName ?collab ?collabName ?choreo ?choreoName WHERE {
  ?defs a bboExt:Definitions .
  ?defs tai:belongsTo ?model .
  ?model tai:originalId "262d9e9b8c224d918fe800cd2a454ddf" .
  OPTIONAL { ?defs bbo:name ?defsName . }
  OPTIONAL {
    ?collab a bboExt:Collaboration .
    ?collab tai:belongsTo ?defs .
    OPTIONAL { ?collab bbo:name ?collabName . }
  }
  OPTIONAL {
    ?choreo a bboExt:Choreography .
    ?choreo tai:belongsTo ?defs .
    OPTIONAL { ?choreo bbo:name ?choreoName . }
  }
}
LIMIT 20

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?msg ?sourceRef ?targetRef ?msgRef WHERE {
  ?msg a bboExt:MessageFlow .
  OPTIONAL { ?msg bboExt:sourceRef ?sourceRef . }
  OPTIONAL { ?msg bboExt:targetRef ?targetRef . }
  OPTIONAL { ?msg bboExt:messageRef ?msgRef . }
  ?msg tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_ece51571_13ba_41d8_8688_057c876cc093> .
}
LIMIT 20
